1	import { quote, claim, type Item } from "./claim-office.js";
2	
3	type QuoteStep = { op: "quote"; items: Item[] };
4	type ClaimStep = {
5	  op: "claim";
6	  policy: number;
7	  incident: { damages: { itemType: string; amount: number }[] };
8	};
9	type Step = QuoteStep | ClaimStep;
10	
11	const chunks: Buffer[] = [];
12	process.stdin.on("data", (c) => chunks.push(c));
13	const KNOWN_TYPES = ["sword", "amulet", "staff", "potion", "rune", "moonstone"];
14	process.stdin.on("end", () => {
15	  const input = JSON.parse(Buffer.concat(chunks).toString("utf-8"));
16	  const customer = input.customer;
17	  const policies: Record<number, { items: Item[]; remainingCap: number | undefined }> = {};
18	  const results: unknown[] = [];
19	  for (let i = 0; i < (input.steps as Step[]).length; i++) {
20	    const step = (input.steps as Step[])[i];
21	    if (step.op === "quote") {
22	      const unknown = step.items.find((it) => !KNOWN_TYPES.includes(it.type));
23	      if (unknown) {
24	        process.stderr.write(`Unknown item type: ${unknown.type}\n`);
25	        process.exit(1);
26	      }
27	      policies[i] = { items: step.items, remainingCap: undefined };
28	      results.push({ premium: quote({ items: step.items, customer }) });
29	    } else {
30	      const policy = policies[step.policy];
31	      const policyTypes = policy.items.map((it) => it.type);
32	      const badDamage = step.incident.damages.find((d) => !policyTypes.includes(d.itemType));
33	      if (badDamage) {
34	        process.stderr.write(`Damage references item not in policy: ${badDamage.itemType}\n`);
35	        process.exit(1);
36	      }
37	      const out = claim({
38	        items: policy.items,
39	        damages: step.incident.damages,
40	        remainingCap: policy.remainingCap,
41	      });
42	      policy.remainingCap = out.remainingCap;
43	      results.push({ payout: out.payout, remainingCap: out.remainingCap });
44	    }
45	  }
46	  process.stdout.write(JSON.stringify({ results }));
47	});
